VALUES
  ('optician-moex-00949', 'optician', 'optician-moex-110-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關隱形眼鏡誘發之乳突狀結膜炎（papillaryconjunctivitis）的敘述，下列何者正確？', '["其機轉為延遲性過敏反應及機械性傷害，因此硬式鏡片發生率較高", "拋棄式比傳統軟式隱形眼鏡之發生率較低", "強效類固醇是治療的首選", "減少配戴時間並無法改善，唯有停戴才可改善其症狀"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "79a1785aebea", "answer_pdf_sha1": "c0d5dd75a323", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00950', 'optician', 'optician-moex-110-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '隱形眼鏡沉積物（deposits）當中，下列何者最常引起視力模糊？', '["脂質（lipid）", "鈣（calcium）", "無機碎片（inorganicdebris）", "溶菌酶（lysozyme）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "79a1785aebea", "answer_pdf_sha1": "c0d5dd75a323", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00951', 'optician', 'optician-moex-110-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列何者不是隱形眼鏡誘發之上輪部角結膜炎（contact-lens-induced superior limbic keratoconjunctivitis, CLSLK）原因？', '["硫柳汞毒性", "機械作用", "鏡片沉積物", "角膜潰瘍"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "79a1785aebea", "answer_pdf_sha1": "c0d5dd75a323", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 42, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00952', 'optician', 'optician-moex-110-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '使用隱形眼鏡時產生流淚、紅眼、畏光、視力模糊時，下列何種處置最適當？', '["立即拿掉隱形眼鏡，並攜帶此隱形眼鏡和隱形眼鏡盒求診", "繼續戴著隱形眼鏡並求診，醫師才會知道鏡片在眼睛的情形，做出有利診斷與治療", "先到藥局買藥水使用，以減緩不適", "觀察數日，確定病情越來越嚴重時再求診，才不會浪費醫療資源"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "79a1785aebea", "answer_pdf_sha1": "c0d5dd75a323", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 43, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00953', 'optician', 'optician-moex-110-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列關於鞏膜鏡驗配過緊的敘述，何者錯誤？', '["可能鏡片和眼睛的關係會從原本正常的半封閉（semiseal）狀態變為封閉狀態（completesealfit）", "鏡片內和鏡片外的液體不易交換", "代謝物和細胞的雜質會累積在鏡片內造成角膜毒性", "在鏡片下輪狀部周圍（paralimbalarea）的區域會變白"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "79a1785aebea", "answer_pdf_sha1": "c0d5dd75a323", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 44, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00954', 'optician', 'optician-moex-110-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關於硬式非球面多焦點隱形眼鏡（asphericmultifocal），下列敘述何者正確？', '["與軟式隱形眼鏡鏡片相比，硬式非球面多焦點隱形眼鏡的光學品質較差", "硬式非球面多焦點隱形眼鏡，為比角膜K值更陡的薄透鏡設計，主要是為了讓鏡片基弧產生多一點的正 度數", "硬式非球面多焦點隱形眼鏡的驗配成功率經統計一般小於50%", "配戴硬式非球面多焦點隱形眼鏡，在眨眼時鏡片滑動約為1mm，為最佳的鏡片滑動情況"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "79a1785aebea", "answer_pdf_sha1": "c0d5dd75a323", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 45, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00955', 'optician', 'optician-moex-110-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列有關非球面老花隱形眼鏡設計之敘述，何者正確？', '["非球面老花隱形眼鏡設計，是依據度數的分布來進行區分，如果在鏡片中心為最大正值（最小負值）， 為中央看遠的鏡片設計", "藉由後表面非球面而產生近閱讀加入度所設計的鏡片，大多常見於軟式隱形眼鏡鏡片", "前表面中央看近的軟式非球面鏡片設計中，如果老花的度數更加深時，其前表面曲率必須有更大的非球 面性，以便在整個光學系統中提供更多的負屈光度數", "如在硬式後表面非球面設計的鏡片中，因為鏡片後表面非球面設計會產生高偏心率（higher-eccentricity）， 故在驗配此種鏡片時，要將鏡片的基弧配的陡一點，以獲得較適當的鏡片定位"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "79a1785aebea", "answer_pdf_sha1": "c0d5dd75a323", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 46, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00956', 'optician', 'optician-moex-110-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關硬式非球面多焦點隱形眼鏡驗配，下列敘述何者錯誤？', '["下眼瞼鬆弛不適合配戴", "瞳孔過大夜間會造成眩光", "通常通過瞳孔同時矯正看近和看遠視力", "驗配時如果鏡片偏心定位，可使用較大直徑來改善"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "79a1785aebea", "answer_pdf_sha1": "c0d5dd75a323", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 47, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00957', 'optician', 'optician-moex-110-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '隱形眼鏡的老花眼矯正，下列敘述何者錯誤？', '["交替視覺雙焦隱形眼鏡多數為硬式鏡片", "同步視覺隱形眼鏡多數為軟式鏡片", "同步視覺隱形眼鏡需配的較不滑動", "驗配狀況都很理想的情況下，同步視覺較交替視覺的視力較佳"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "79a1785aebea", "answer_pdf_sha1": "c0d5dd75a323", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 48, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00958', 'optician', 'optician-moex-110-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於軟式老花隱形眼鏡的分類，下列何者錯誤？', '["常可分為雙焦和多焦", "依鏡片設計可分中間看近（center-near）、中間看遠（center-distance）、轉換（translating）設計", "轉換設計在硬式隱形眼鏡比起軟式隱形眼鏡常見", "轉換設計的視力品質比其他兩種設計差"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "79a1785aebea", "answer_pdf_sha1": "c0d5dd75a323", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 49, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
